import crypto from "crypto";
import type { Pool } from "pg";

interface TopicQuestions {
  topic: string;
  bodySystem: string;
  subtopic: string;
  catQuestions: { stem: string; options: string[]; correctAnswer: number[]; rationale: string; difficulty: number }[];
  flashcards: { front: string; back: string; rationale: string }[];
}

function hashStem(stem: string): string {
  return crypto.createHash("sha256").update(stem.trim().toLowerCase()).digest("hex").substring(0, 32);
}

