      { front: "How does sepsis trigger DIC?", back: "Bacterial endotoxins activate tissue factor expression on monocytes and endothelium, triggering widespread coagulation cascade activation", rationale: "Simultaneously, inflammatory cytokines downregulate natural anticoagulants (protein C, antithrombin) and impair fibrinolysis." },
      { front: "What is the ISTH DIC score?", back: "Scoring system (0-8): platelets (0-2), D-dimer (0-3), fibrinogen (0-1), PT prolongation (0-2). Score ≥5 = overt DIC", rationale: "Serial scoring helps track progression and treatment response." },
      { front: "What complications result from microvascular thrombosis in DIC?", back: "Renal failure (oliguria), hepatic failure, ARDS, digital/extremity ischemia, altered mental status, adrenal hemorrhage", rationale: "Multi-organ failure from microvascular thrombosis is a major cause of DIC mortality." },
      { front: "When might heparin be used in DIC?", back: "Chronic/compensated DIC with predominant thrombosis (malignancy-related), purpura fulminans, or arterial/venous thrombosis", rationale: "Controversial. Never used when hemorrhage predominates. Requires careful monitoring." },
      { front: "What is the mortality rate of DIC?", back: "30-50% overall; higher in sepsis-associated DIC and with delayed treatment of the underlying cause", rationale: "Mortality reflects both DIC severity and the underlying trigger. Early recognition and treatment improve outcomes." },
      { front: "What blood products treat DIC?", back: "Cryoprecipitate (fibrinogen), FFP (all factors), platelets (for thrombocytopenia), PRBCs (for anemia from hemorrhage)", rationale: "Guided by lab values and clinical bleeding. Replace what's consumed." },
      { front: "What is fibrinogen's role in clotting?", back: "Factor I — converted to fibrin by thrombin to form the structural mesh of blood clots", rationale: "Low fibrinogen (<100) means insufficient substrate for clot formation. Cryoprecipitate is the most concentrated source." },
      { front: "How does DIC differ from TTP/HUS?", back: "DIC: consumptive (low fibrinogen, prolonged PT). TTP/HUS: thrombotic microangiopathy with NORMAL fibrinogen and PT", rationale: "This distinction is critical because treatment differs: DIC = treat cause + replace factors; TTP = plasma exchange." }
